   597→// NewClient returns a http.Client using the specified http.RoundTripper.
   598→func newClient(rt http.RoundTripper) *http.Client {
   599→	return &http.Client{Transport: rt}
   600→}
   601→
   602→// NewClientFromConfig returns a new HTTP client configured for the
   603→// given config.HTTPClientConfig and config.HTTPClientOption.
   604→// The name is used as go-conntrack metric label.
   605→func NewClientFromConfig(cfg HTTPClientConfig, name string, optFuncs ...HTTPClientOption) (*http.Client, error) {
   606→	rt, err := NewRoundTripperFromConfig(cfg, name, optFuncs...)
   607→	if err != nil {
   608→		return nil, err
   609→	}
   610→	client := newClient(rt)
   611→	if !cfg.FollowRedirects {
   612→		client.CheckRedirect = func(*http.Request, []*http.Request) error {
   613→			return http.ErrUseLastResponse
   614→		}
   615→	}
   616→	return client, nil
   617→}
   618→
   619→// NewRoundTripperFromConfig returns a new HTTP RoundTripper configured for the
   620→// given config.HTTPClientConfig and config.HTTPClientOption.
   621→// The name is used as go-conntrack metric label.
   622→func NewRoundTripperFromConfig(cfg HTTPClientConfig, name string, optFuncs ...HTTPClientOption) (http.RoundTripper, error) {
   623→	return NewRoundTripperFromConfigWithContext(context.Background(), cfg, name, optFuncs...)
   624→}
   625→
   626→// NewRoundTripperFromConfigWithContext returns a new HTTP RoundTripper configured for the
   627→// given config.HTTPClientConfig and config.HTTPClientOption.
   628→// The name is used as go-conntrack metric label.
   629→func NewRoundTripperFromConfigWithContext(ctx context.Context, cfg HTTPClientConfig, name string, optFuncs ...HTTPClientOption) (http.RoundTripper, error) {
   630→	opts := defaultHTTPClientOptions
   631→	for _, opt := range optFuncs {
   632→		opt.applyToHTTPClientOptions(&opts)
   633→	}
   634→
   635→	var dialContext func(ctx context.Context, network, addr string) (net.Conn, error)
   636→
   637→	if opts.dialContextFunc != nil {
   638→		dialContext = conntrack.NewDialContextFunc(
   639→			conntrack.DialWithDialContextFunc((func(context.Context, string, string) (net.Conn, error))(opts.dialContextFunc)),
   640→			conntrack.DialWithTracing(),
   641→			conntrack.DialWithName(name))
   642→	} else {
   643→		dialContext = conntrack.NewDialContextFunc(
   644→			conntrack.DialWithTracing(),
   645→			conntrack.DialWithName(name))
   646→	}
   647→
   648→	newRT := func(tlsConfig *tls.Config) (http.RoundTripper, error) {
   649→		// The only timeout we care about is the configured scrape timeout.
   650→		// It is applied on request. So we leave out any timings here.
   651→		var rt http.RoundTripper = &http.Transport{
   652→			Proxy:                 cfg.Proxy(),
   653→			ProxyConnectHeader:    cfg.GetProxyConnectHeader(),
   654→			MaxIdleConns:          20000,
   655→			MaxIdleConnsPerHost:   1000, // see https://github.com/golang/go/issues/13801
   656→			DisableKeepAlives:     !opts.keepAlivesEnabled,
   657→			TLSClientConfig:       tlsConfig,
   658→			DisableCompression:    true,
   659→			IdleConnTimeout:       opts.idleConnTimeout,
   660→			TLSHandshakeTimeout:   10 * time.Second,
   661→			ExpectContinueTimeout: 1 * time.Second,
   662→			DialContext:           dialContext,
   663→		}
   664→		if opts.http2Enabled && cfg.EnableHTTP2 {
   665→			http2t, err := http2.ConfigureTransports(rt.(*http.Transport))
   666→			if err != nil {
   667→				return nil, err
   668→			}
   669→			http2t.ReadIdleTimeout = time.Minute
   670→		}
   671→
   672→		// If a authorization_credentials is provided, create a round tripper that will set the
   673→		// Authorization header correctly on each request.
   674→		if cfg.Authorization != nil {
   675→			credentialsSecret, err := toSecret(opts.secretManager, cfg.Authorization.Credentials, cfg.Authorization.CredentialsFile, cfg.Authorization.CredentialsRef)
   676→			if err != nil {
   677→				return nil, fmt.Errorf("unable to use credentials: %w", err)
   678→			}
   679→			rt = NewAuthorizationCredentialsRoundTripper(cfg.Authorization.Type, credentialsSecret, rt)
   680→		}
   681→		// Backwards compatibility, be nice with importers who would not have
   682→		// called Validate().
   683→		if len(cfg.BearerToken) > 0 || len(cfg.BearerTokenFile) > 0 {
   684→			bearerSecret, err := toSecret(opts.secretManager, cfg.BearerToken, cfg.BearerTokenFile, "")
   685→			if err != nil {
   686→				return nil, fmt.Errorf("unable to use bearer token: %w", err)
   687→			}
   688→			rt = NewAuthorizationCredentialsRoundTripper("Bearer", bearerSecret, rt)
   689→		}
   690→
   691→		if cfg.BasicAuth != nil {
   692→			usernameSecret, err := toSecret(opts.secretManager, Secret(cfg.BasicAuth.Username), cfg.BasicAuth.UsernameFile, cfg.BasicAuth.UsernameRef)
   693→			if err != nil {
   694→				return nil, fmt.Errorf("unable to use username: %w", err)
   695→			}
   696→			passwordSecret, err := toSecret(opts.secretManager, cfg.BasicAuth.Password, cfg.BasicAuth.PasswordFile, cfg.BasicAuth.PasswordRef)
   697→			if err != nil {
   698→				return nil, fmt.Errorf("unable to use password: %w", err)
   699→			}
   700→			rt = NewBasicAuthRoundTripper(usernameSecret, passwordSecret, rt)
   701→		}
   702→
   703→		if cfg.OAuth2 != nil {
   704→			var (
   705→				oauthCredential SecretReader
   706→				err             error
   707→			)
   708→
   709→			if cfg.OAuth2.GrantType == grantTypeJWTBearer {
   710→				oauthCredential, err = toSecret(opts.secretManager, cfg.OAuth2.ClientCertificateKey, cfg.OAuth2.ClientCertificateKeyFile, cfg.OAuth2.ClientCertificateKeyRef)
   711→				if err != nil {
   712→					return nil, fmt.Errorf("unable to use client certificate: %w", err)
   713→				}
   714→			} else {
   715→				oauthCredential, err = toSecret(opts.secretManager, cfg.OAuth2.ClientSecret, cfg.OAuth2.ClientSecretFile, cfg.OAuth2.ClientSecretRef)
   716→				if err != nil {
   717→					return nil, fmt.Errorf("unable to use client secret: %w", err)
   718→				}
   719→			}
   720→			rt = NewOAuth2RoundTripper(oauthCredential, cfg.OAuth2, rt, &opts)
   721→		}
   722→
   723→		if cfg.HTTPHeaders != nil {
   724→			rt = NewHeadersRoundTripper(cfg.HTTPHeaders, rt)
   725→		}
   726→
   727→		if opts.userAgent != "" {
   728→			rt = NewUserAgentRoundTripper(opts.userAgent, rt)
   729→		}
   730→
   731→		if opts.host != "" {
   732→			rt = NewHostRoundTripper(opts.host, rt)
   733→		}
   734→
   735→		// Return a new configured RoundTripper.
   736→		return rt, nil
   737→	}
   738→
   739→	tlsConfig, err := opts.newTLSConfigFunc(ctx, &cfg.TLSConfig, WithSecretManager(opts.secretManager))
   740→	if err != nil {
   741→		return nil, err
   742→	}
   743→
   744→	tlsSettings, err := cfg.TLSConfig.roundTripperSettings(opts.secretManager)
   745→	if err != nil {
   746→		return nil, err
   747→	}
   748→
   749→	if tlsSettings.immutable() {
   750→		// No need for a RoundTripper that reloads the files automatically.
   751→		return newRT(tlsConfig)
   752→	}
   753→	return NewTLSRoundTripperWithContext(ctx, tlsConfig, tlsSettings, newRT)
   754→}
