   756→// SecretManager manages secret data mapped to names known as "references" or "refs".
   757→type SecretManager interface {
   758→	// Fetch returns the secret data given a secret name indicated by `secretRef`.
   759→	Fetch(ctx context.Context, secretRef string) (string, error)
   760→}
