  1109→// cloneRequest returns a clone of the provided *http.Request.
  1110→// The clone is a shallow copy of the struct and its Header map.
  1111→func cloneRequest(r *http.Request) *http.Request {
  1112→	// Shallow copy of the struct.
  1113→	r2 := new(http.Request)
  1114→	*r2 = *r
  1115→	// Deep copy of the Header.
  1116→	r2.Header = make(http.Header)
  1117→	for k, s := range r.Header {
  1118→		r2.Header[k] = s
  1119→	}
  1120→	return r2
