  1348→// tlsRoundTripper is a RoundTripper that updates automatically its TLS
  1349→// configuration whenever the content of the CA file changes.
  1350→type tlsRoundTripper struct {
  1351→	settings TLSRoundTripperSettings
  1352→
  1353→	// newRT returns a new RoundTripper.
  1354→	newRT func(*tls.Config) (http.RoundTripper, error)
  1355→
  1356→	mtx          sync.RWMutex
  1357→	rt           http.RoundTripper
  1358→	hashCAData   []byte
  1359→	hashCertData []byte
  1360→	hashKeyData  []byte
  1361→	tlsConfig    *tls.Config
  1362→}
  1363→
  1364→type TLSRoundTripperSettings struct {
  1365→	CA   SecretReader
  1366→	Cert SecretReader
  1367→	Key  SecretReader
  1368→}
  1369→
  1370→func (t *TLSRoundTripperSettings) immutable() bool {
  1371→	return (t.CA == nil || t.CA.Immutable()) && (t.Cert == nil || t.Cert.Immutable()) && (t.Key == nil || t.Key.Immutable())
  1372→}
  1373→
  1374→func NewTLSRoundTripper(
  1375→	cfg *tls.Config,
  1376→	settings TLSRoundTripperSettings,
  1377→	newRT func(*tls.Config) (http.RoundTripper, error),
  1378→) (http.RoundTripper, error) {
  1379→	return NewTLSRoundTripperWithContext(context.Background(), cfg, settings, newRT)
  1380→}
  1381→
  1382→func NewTLSRoundTripperWithContext(
  1383→	ctx context.Context,
  1384→	cfg *tls.Config,
  1385→	settings TLSRoundTripperSettings,
  1386→	newRT func(*tls.Config) (http.RoundTripper, error),
  1387→) (http.RoundTripper, error) {
  1388→	t := &tlsRoundTripper{
  1389→		settings:  settings,
  1390→		newRT:     newRT,
  1391→		tlsConfig: cfg,
  1392→	}
  1393→
  1394→	rt, err := t.newRT(t.tlsConfig)
  1395→	if err != nil {
  1396→		return nil, err
  1397→	}
  1398→	t.rt = rt
  1399→	_, t.hashCAData, t.hashCertData, t.hashKeyData, err = t.getTLSDataWithHash(ctx)
  1400→	if err != nil {
  1401→		return nil, err
  1402→	}
  1403→
  1404→	return t, nil
  1405→}
  1406→
  1407→func (t *tlsRoundTripper) getTLSDataWithHash(ctx context.Context) ([]byte, []byte, []byte, []byte, error) {
  1408→	var caBytes, certBytes, keyBytes []byte
  1409→
  1410→	if t.settings.CA != nil {
  1411→		ca, err := t.settings.CA.Fetch(ctx)
  1412→		if err != nil {
  1413→			return nil, nil, nil, nil, fmt.Errorf("unable to read CA cert: %w", err)
  1414→		}
  1415→		caBytes = []byte(ca)
  1416→	}
  1417→
  1418→	if t.settings.Cert != nil {
  1419→		cert, err := t.settings.Cert.Fetch(ctx)
  1420→		if err != nil {
  1421→			return nil, nil, nil, nil, fmt.Errorf("unable to read client cert: %w", err)
  1422→		}
  1423→		certBytes = []byte(cert)
  1424→	}
  1425→
  1426→	if t.settings.Key != nil {
  1427→		key, err := t.settings.Key.Fetch(ctx)
  1428→		if err != nil {
  1429→			return nil, nil, nil, nil, fmt.Errorf("unable to read client key: %w", err)
  1430→		}
  1431→		keyBytes = []byte(key)
  1432→	}
  1433→
  1434→	var caHash, certHash, keyHash [32]byte
  1435→
  1436→	if len(caBytes) > 0 {
  1437→		caHash = sha256.Sum256(caBytes)
  1438→	}
  1439→	if len(certBytes) > 0 {
  1440→		certHash = sha256.Sum256(certBytes)
  1441→	}
  1442→	if len(keyBytes) > 0 {
  1443→		keyHash = sha256.Sum256(keyBytes)
  1444→	}
  1445→
  1446→	return caBytes, caHash[:], certHash[:], keyHash[:], nil
  1447→}
  1448→
  1449→// RoundTrip implements the http.RoundTrip interface.
  1450→func (t *tlsRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
  1451→	caData, caHash, certHash, keyHash, err := t.getTLSDataWithHash(req.Context())
  1452→	if err != nil {
  1453→		return nil, err
  1454→	}
  1455→
  1456→	t.mtx.RLock()
  1457→	equal := bytes.Equal(caHash, t.hashCAData) &&
  1458→		bytes.Equal(certHash, t.hashCertData) &&
  1459→		bytes.Equal(keyHash, t.hashKeyData)
  1460→	rt := t.rt
  1461→	t.mtx.RUnlock()
  1462→	if equal {
  1463→		// The CA cert hasn't changed, use the existing RoundTripper.
  1464→		return rt.RoundTrip(req)
  1465→	}
  1466→
  1467→	// Create a new RoundTripper.
  1468→	// The cert and key files are read separately by the client
  1469→	// using GetClientCertificate.
  1470→	tlsConfig := t.tlsConfig.Clone()
  1471→	if !updateRootCA(tlsConfig, caData) {
  1472→		if t.settings.CA == nil {
  1473→			return nil, errors.New("unable to use specified CA cert: none configured")
  1474→		}
  1475→		return nil, fmt.Errorf("unable to use specified CA cert %s", t.settings.CA.Description())
  1476→	}
  1477→	rt, err = t.newRT(tlsConfig)
  1478→	if err != nil {
  1479→		return nil, err
  1480→	}
  1481→	t.CloseIdleConnections()
  1482→
  1483→	t.mtx.Lock()
  1484→	t.rt = rt
  1485→	t.hashCAData = caHash
  1486→	t.hashCertData = certHash
  1487→	t.hashKeyData = keyHash
  1488→	t.mtx.Unlock()
  1489→
  1490→	return rt.RoundTrip(req)
  1491→}
  1492→
  1493→func (t *tlsRoundTripper) CloseIdleConnections() {
  1494→	t.mtx.RLock()
  1495→	defer t.mtx.RUnlock()
  1496→	if ci, ok := t.rt.(closeIdler); ok {
  1497→		ci.CloseIdleConnections()
  1498→	}
  1499→}
