  1554→type ProxyConfig struct {
  1555→	// HTTP proxy server to use to connect to the targets.
  1556→	ProxyURL URL `yaml:"proxy_url,omitempty" json:"proxy_url,omitempty"`
  1557→	// NoProxy contains addresses that should not use a proxy.
  1558→	NoProxy string `yaml:"no_proxy,omitempty" json:"no_proxy,omitempty"`
  1559→	// ProxyFromEnvironment makes use of net/http ProxyFromEnvironment function
  1560→	// to determine proxies.
  1561→	ProxyFromEnvironment bool `yaml:"proxy_from_environment,omitempty" json:"proxy_from_environment,omitempty"`
  1562→	// ProxyConnectHeader optionally specifies headers to send to
  1563→	// proxies during CONNECT requests. Assume that at least _some_ of
  1564→	// these headers are going to contain secrets and use Secret as the
  1565→	// value type instead of string.
  1566→	ProxyConnectHeader ProxyHeader `yaml:"proxy_connect_header,omitempty" json:"proxy_connect_header,omitempty"`
  1567→
  1568→	proxyFunc func(*http.Request) (*url.URL, error)
  1569→}
  1570→
  1571→// UnmarshalYAML implements the yaml.Unmarshaler interface.
  1572→func (c *ProxyConfig) Validate() error {
  1573→	if len(c.ProxyConnectHeader) > 0 && (!c.ProxyFromEnvironment && (c.ProxyURL.URL == nil || c.ProxyURL.String() == "")) {
  1574→		return errors.New("if proxy_connect_header is configured, proxy_url or proxy_from_environment must also be configured")
  1575→	}
  1576→	if c.ProxyFromEnvironment && c.ProxyURL.URL != nil && c.ProxyURL.String() != "" {
  1577→		return errors.New("if proxy_from_environment is configured, proxy_url must not be configured")
  1578→	}
  1579→	if c.ProxyFromEnvironment && c.NoProxy != "" {
  1580→		return errors.New("if proxy_from_environment is configured, no_proxy must not be configured")
  1581→	}
  1582→	if c.ProxyURL.URL == nil && c.NoProxy != "" {
  1583→		return errors.New("if no_proxy is configured, proxy_url must also be configured")
  1584→	}
  1585→	return nil
  1586→}
  1587→
  1588→// Proxy returns the Proxy URL for a request.
  1589→func (c *ProxyConfig) Proxy() (fn func(*http.Request) (*url.URL, error)) {
  1590→	if c == nil {
  1591→		return nil
  1592→	}
  1593→	defer func() {
  1594→		fn = c.proxyFunc
  1595→	}()
  1596→	if c.proxyFunc != nil {
  1597→		return fn
  1598→	}
  1599→	if c.ProxyFromEnvironment {
  1600→		proxyFn := httpproxy.FromEnvironment().ProxyFunc()
  1601→		c.proxyFunc = func(req *http.Request) (*url.URL, error) {
  1602→			return proxyFn(req.URL)
  1603→		}
  1604→		return fn
  1605→	}
  1606→	if c.ProxyURL.URL != nil && c.ProxyURL.String() != "" {
  1607→		if c.NoProxy == "" {
  1608→			c.proxyFunc = http.ProxyURL(c.ProxyURL.URL)
  1609→			return fn
  1610→		}
  1611→		proxy := &httpproxy.Config{
  1612→			HTTPProxy:  c.ProxyURL.String(),
  1613→			HTTPSProxy: c.ProxyURL.String(),
  1614→			NoProxy:    c.NoProxy,
  1615→		}
  1616→		proxyFn := proxy.ProxyFunc()
  1617→		c.proxyFunc = func(req *http.Request) (*url.URL, error) {
  1618→			return proxyFn(req.URL)
  1619→		}
  1620→	}
  1621→	return fn
  1622→}
  1623→
  1624→// ProxyConnectHeader() return the Proxy Connext Headers.
  1625→func (c *ProxyConfig) GetProxyConnectHeader() http.Header {
  1626→	return c.ProxyConnectHeader.HTTPHeader()
  1627→}
