   375→// nonZeroCount returns the amount of values that are non-zero.
   376→func nonZeroCount[T comparable](values ...T) int {
   377→	count := 0
   378→	var zero T
   379→	for _, value := range values {
   380→		if value != zero {
   381→			count++
   382→		}
   383→	}
   384→	return count
   385→}
