   387→// Validate validates the HTTPClientConfig to check only one of BearerToken,
   388→// BasicAuth and BearerTokenFile is configured. It also validates that ProxyURL
   389→// is set if ProxyConnectHeader is set.
   390→func (c *HTTPClientConfig) Validate() error {
   391→	// Backwards compatibility with the bearer_token field.
   392→	if len(c.BearerToken) > 0 && len(c.BearerTokenFile) > 0 {
   393→		return errors.New("at most one of bearer_token & bearer_token_file must be configured")
   394→	}
   395→	if (c.BasicAuth != nil || c.OAuth2 != nil) && (len(c.BearerToken) > 0 || len(c.BearerTokenFile) > 0) {
   396→		return errors.New("at most one of basic_auth, oauth2, bearer_token & bearer_token_file must be configured")
   397→	}
   398→	if c.BasicAuth != nil && nonZeroCount(c.BasicAuth.Username != "", c.BasicAuth.UsernameFile != "", c.BasicAuth.UsernameRef != "") > 1 {
   399→		return errors.New("at most one of basic_auth username, username_file & username_ref must be configured")
   400→	}
   401→	if c.BasicAuth != nil && nonZeroCount(string(c.BasicAuth.Password) != "", c.BasicAuth.PasswordFile != "", c.BasicAuth.PasswordRef != "") > 1 {
   402→		return errors.New("at most one of basic_auth password, password_file & password_ref must be configured")
   403→	}
   404→	if c.Authorization != nil {
   405→		if len(c.BearerToken) > 0 || len(c.BearerTokenFile) > 0 {
   406→			return errors.New("authorization is not compatible with bearer_token & bearer_token_file")
   407→		}
   408→		if nonZeroCount(string(c.Authorization.Credentials) != "", c.Authorization.CredentialsFile != "", c.Authorization.CredentialsRef != "") > 1 {
   409→			return errors.New("at most one of authorization credentials & credentials_file must be configured")
   410→		}
   411→		c.Authorization.Type = strings.TrimSpace(c.Authorization.Type)
   412→		if len(c.Authorization.Type) == 0 {
   413→			c.Authorization.Type = "Bearer"
   414→		}
   415→		if strings.ToLower(c.Authorization.Type) == "basic" {
   416→			return errors.New(`authorization type cannot be set to "basic", use "basic_auth" instead`)
   417→		}
   418→		if c.BasicAuth != nil || c.OAuth2 != nil {
   419→			return errors.New("at most one of basic_auth, oauth2 & authorization must be configured")
   420→		}
   421→	} else {
   422→		if len(c.BearerToken) > 0 {
   423→			c.Authorization = &Authorization{Credentials: c.BearerToken}
   424→			c.Authorization.Type = "Bearer"
   425→			c.BearerToken = ""
   426→		}
   427→		if len(c.BearerTokenFile) > 0 {
   428→			c.Authorization = &Authorization{CredentialsFile: c.BearerTokenFile}
   429→			c.Authorization.Type = "Bearer"
   430→			c.BearerTokenFile = ""
   431→		}
   432→	}
   433→	if c.OAuth2 != nil {
   434→		if c.BasicAuth != nil {
   435→			return errors.New("at most one of basic_auth, oauth2 & authorization must be configured")
   436→		}
   437→		if len(c.OAuth2.ClientID) == 0 {
   438→			return errors.New("oauth2 client_id must be configured")
   439→		}
   440→		if len(c.OAuth2.TokenURL) == 0 {
   441→			return errors.New("oauth2 token_url must be configured")
   442→		}
   443→		if c.OAuth2.GrantType == grantTypeJWTBearer {
   444→			if nonZeroCount(len(c.OAuth2.ClientCertificateKey) > 0, len(c.OAuth2.ClientCertificateKeyFile) > 0, len(c.OAuth2.ClientCertificateKeyRef) > 0) > 1 {
   445→				return errors.New("at most one of oauth2 client_certificate_key, client_certificate_key_file & client_certificate_key_ref must be configured using grant-type=urn:ietf:params:oauth:grant-type:jwt-bearer")
   446→			}
   447→			if c.OAuth2.SignatureAlgorithm != "" && !slices.Contains(validSignatureAlgorithm, c.OAuth2.SignatureAlgorithm) {
   448→				return errors.New("valid signature algorithms are RS256, RS384 and RS512")
   449→			}
   450→		} else if nonZeroCount(len(c.OAuth2.ClientSecret) > 0, len(c.OAuth2.ClientSecretFile) > 0, len(c.OAuth2.ClientSecretRef) > 0) > 1 {
   451→			return errors.New("at most one of oauth2 client_secret, client_secret_file & client_secret_ref must be configured using grant-type=client_credentials")
   452→		}
   453→	}
   454→	if err := c.ProxyConfig.Validate(); err != nil {
   455→		return err
   456→	}
   457→	if c.HTTPHeaders != nil {
   458→		if err := c.HTTPHeaders.Validate(); err != nil {
   459→			return err
   460→		}
   461→	}
   462→	return nil
   463→}
