   963→func (rt *oauth2RoundTripper) newOauth2TokenSource(req *http.Request, clientCredential string) (client *http.Client, source oauth2.TokenSource, err error) {
   964→	tlsConfig, err := NewTLSConfig(&rt.config.TLSConfig, WithSecretManager(rt.opts.secretManager))
   965→	if err != nil {
   966→		return nil, nil, err
   967→	}
   968→
   969→	tlsTransport := func(tlsConfig *tls.Config) (http.RoundTripper, error) {
   970→		return &http.Transport{
   971→			TLSClientConfig:       tlsConfig,
   972→			Proxy:                 rt.config.Proxy(),
   973→			ProxyConnectHeader:    rt.config.GetProxyConnectHeader(),
   974→			DisableKeepAlives:     !rt.opts.keepAlivesEnabled,
   975→			MaxIdleConns:          20,
   976→			MaxIdleConnsPerHost:   1, // see https://github.com/golang/go/issues/13801
   977→			IdleConnTimeout:       10 * time.Second,
   978→			TLSHandshakeTimeout:   10 * time.Second,
   979→			ExpectContinueTimeout: 1 * time.Second,
   980→		}, nil
   981→	}
   982→
   983→	var t http.RoundTripper
   984→	tlsSettings, err := rt.config.TLSConfig.roundTripperSettings(rt.opts.secretManager)
   985→	if err != nil {
   986→		return nil, nil, err
   987→	}
   988→	if tlsSettings.immutable() {
   989→		t, _ = tlsTransport(tlsConfig)
   990→	} else {
   991→		t, err = NewTLSRoundTripperWithContext(req.Context(), tlsConfig, tlsSettings, tlsTransport)
   992→		if err != nil {
   993→			return nil, nil, err
   994→		}
   995→	}
   996→
   997→	if ua := req.UserAgent(); ua != "" {
   998→		t = NewUserAgentRoundTripper(ua, t)
   999→	}
  1000→
  1001→	var config oauth2TokenSourceConfig
  1002→
  1003→	if rt.config.GrantType == grantTypeJWTBearer {
  1004→		// RFC 7523 3.1 - JWT authorization grants
  1005→		// RFC 7523 3.2 - Client Authentication Processing is not implement upstream yet,
  1006→		// see https://github.com/golang/oauth2/pull/745
  1007→
  1008→		var sig *jwt.SigningMethodRSA
  1009→		switch rt.config.SignatureAlgorithm {
  1010→		case jwt.SigningMethodRS256.Name:
  1011→			sig = jwt.SigningMethodRS256
  1012→		case jwt.SigningMethodRS384.Name:
  1013→			sig = jwt.SigningMethodRS384
  1014→		case jwt.SigningMethodRS512.Name:
  1015→			sig = jwt.SigningMethodRS512
  1016→		default:
  1017→			sig = jwt.SigningMethodRS256
  1018→		}
  1019→
  1020→		iss := rt.config.Iss
  1021→		if iss == "" {
  1022→			iss = rt.config.ClientID
  1023→		}
  1024→		config = &JwtGrantTypeConfig{
  1025→			PrivateKey:       []byte(clientCredential),
  1026→			PrivateKeyID:     rt.config.ClientCertificateKeyID,
  1027→			Scopes:           rt.config.Scopes,
  1028→			TokenURL:         rt.config.TokenURL,
  1029→			SigningAlgorithm: sig,
  1030→			Iss:              iss,
  1031→			Subject:          rt.config.ClientID,
  1032→			Audience:         rt.config.Audience,
  1033→			PrivateClaims:    rt.config.Claims,
  1034→			EndpointParams:   mapToValues(rt.config.EndpointParams),
  1035→		}
  1036→	} else {
  1037→		config = &clientcredentials.Config{
  1038→			ClientID:       rt.config.ClientID,
  1039→			ClientSecret:   clientCredential,
  1040→			Scopes:         rt.config.Scopes,
  1041→			TokenURL:       rt.config.TokenURL,
  1042→			EndpointParams: mapToValues(rt.config.EndpointParams),
  1043→		}
  1044→	}
  1045→	client = &http.Client{Transport: t}
  1046→	ctx := context.WithValue(context.Background(), oauth2.HTTPClient, client)
  1047→	return client, config.TokenSource(ctx), nil
  1048→}
