  1050→func (rt *oauth2RoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
  1051→	var (
  1052→		secret    string
  1053→		needsInit bool
  1054→	)
  1055→
  1056→	rt.mtx.RLock()
  1057→	secret = rt.lastSecret
  1058→	needsInit = rt.lastRT.Source == nil
  1059→	rt.mtx.RUnlock()
  1060→
  1061→	// Fetch the secret if it's our first run or always if the secret can change.
  1062→	if !rt.oauthCredential.Immutable() || needsInit {
  1063→		newSecret, err := rt.oauthCredential.Fetch(req.Context())
  1064→		if err != nil {
  1065→			return nil, fmt.Errorf("unable to read oauth2 client secret: %w", err)
  1066→		}
  1067→		if newSecret != secret || needsInit {
  1068→			// Secret changed or it's a first run. Rebuilt oauth2 setup.
  1069→			client, source, err := rt.newOauth2TokenSource(req, newSecret)
  1070→			if err != nil {
  1071→				return nil, err
  1072→			}
  1073→
  1074→			rt.mtx.Lock()
  1075→			rt.lastSecret = newSecret
  1076→			rt.lastRT.Source = source
  1077→			if rt.client != nil {
  1078→				rt.client.CloseIdleConnections()
  1079→			}
  1080→			rt.client = client
  1081→			rt.mtx.Unlock()
  1082→		}
  1083→	}
  1084→
  1085→	rt.mtx.RLock()
  1086→	currentRT := rt.lastRT
  1087→	rt.mtx.RUnlock()
  1088→	return currentRT.RoundTrip(req)
  1089→}
