  1091→func (rt *oauth2RoundTripper) CloseIdleConnections() {
  1092→	if rt.client != nil {
  1093→		rt.client.CloseIdleConnections()
  1094→	}
  1095→	if ci, ok := rt.lastRT.Base.(closeIdler); ok {
  1096→		ci.CloseIdleConnections()
  1097→	}
  1098→}
