  1250→// Validate validates the TLSConfig to check that only one of the inlined or
  1251→// file-based fields for the TLS CA, client certificate, and client key are
  1252→// used.
  1253→func (c *TLSConfig) Validate() error {
  1254→	if nonZeroCount(len(c.CA) > 0, len(c.CAFile) > 0, len(c.CARef) > 0) > 1 {
  1255→		return errors.New("at most one of ca, ca_file & ca_ref must be configured")
  1256→	}
  1257→	if nonZeroCount(len(c.Cert) > 0, len(c.CertFile) > 0, len(c.CertRef) > 0) > 1 {
  1258→		return errors.New("at most one of cert, cert_file & cert_ref must be configured")
  1259→	}
  1260→	if nonZeroCount(len(c.Key) > 0, len(c.KeyFile) > 0, len(c.KeyRef) > 0) > 1 {
  1261→		return errors.New("at most one of key and key_file must be configured")
  1262→	}
  1263→
  1264→	if c.usingClientCert() && !c.usingClientKey() {
  1265→		return errors.New("exactly one of key or key_file must be configured when a client certificate is configured")
  1266→	} else if c.usingClientKey() && !c.usingClientCert() {
  1267→		return errors.New("exactly one of cert or cert_file must be configured when a client key is configured")
  1268→	}
  1269→
  1270→	return nil
  1271→}
  1272→
  1273→func (c *TLSConfig) usingClientCert() bool {
  1274→	return len(c.Cert) > 0 || len(c.CertFile) > 0 || len(c.CertRef) > 0
  1275→}
  1276→
  1277→func (c *TLSConfig) usingClientKey() bool {
  1278→	return len(c.Key) > 0 || len(c.KeyFile) > 0 || len(c.KeyRef) > 0
