  1281→func (c *TLSConfig) roundTripperSettings(secretManager SecretManager) (TLSRoundTripperSettings, error) {
  1282→	ca, err := toSecret(secretManager, Secret(c.CA), c.CAFile, c.CARef)
  1283→	if err != nil {
  1284→		return TLSRoundTripperSettings{}, err
  1285→	}
  1286→	cert, err := toSecret(secretManager, Secret(c.Cert), c.CertFile, c.CertRef)
  1287→	if err != nil {
  1288→		return TLSRoundTripperSettings{}, err
  1289→	}
  1290→	key, err := toSecret(secretManager, c.Key, c.KeyFile, c.KeyRef)
  1291→	if err != nil {
  1292→		return TLSRoundTripperSettings{}, err
  1293→	}
  1294→	return TLSRoundTripperSettings{
  1295→		CA:   ca,
  1296→		Cert: cert,
